"use client";
import Link from "next/link";
import Image from "next/image";
import styles from "/styles.module.scss"; // Updated path
import { useState, useEffect, useRef, useCallback } from "react";
import Head from "next/head";
import axios from "axios";
import moment from "moment";

interface Article {
  _id: string;
  title: string;
  image: string;
  content: string;
  date: string;
}

interface HomeAdBaiVietProps {}

const HomeAdBaiViet: React.FC<HomeAdBaiVietProps> = () => {
  const [isSidebarHidden, setIsSidebarHidden] = useState(false);
  const sidebarRef = useRef<HTMLElement | null>(null);
  const mainContentRef = useRef<HTMLElement | null>(null);

  const [articles, setArticles] = useState<Article[]>([]);
  const [newArticle, setNewArticle] = useState({
    title: "",
    image: "",
    content: "",
  });
  const [selectedImage, setSelectedImage] = useState<File | null>(null);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  const toggleSidebar = useCallback(() => {
    setIsSidebarHidden((prevState) => !prevState);
  }, []);

  const updateClasses = useCallback(() => {
    const sidebar = sidebarRef.current;
    const mainContent = mainContentRef.current;

    if (sidebar && mainContent) {
      if (isSidebarHidden) {
        sidebar.classList.add(styles.hidden);
        mainContent.classList.add(styles.expanded);
      } else {
        sidebar.classList.remove(styles.hidden);
        mainContent.classList.remove(styles.expanded);
      }
    }
  }, [isSidebarHidden, styles.expanded, styles.hidden]);

  useEffect(() => {
    const fetchArticles = async () => {
      try {
        const response = await axios.get("/api/articles");
        setArticles(response.data);
      } catch (error: any) {
        console.error("Error fetching articles:", error);
        setErrorMessage("Failed to load articles. Please try again.");
      }
    };

    fetchArticles();
  }, []);

  useEffect(() => {
    updateClasses();
  }, [isSidebarHidden, updateClasses]);

  const handleInputChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>
  ) => {
    setNewArticle({ ...newArticle, [e.target.name]: e.target.value });
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setSelectedImage(e.target.files[0]);
    }
  };

  const createArticle = async () => {
    setErrorMessage(null);
    setSuccessMessage(null);

    try {
      const formData = new FormData();
      formData.append("title", newArticle.title);
      formData.append("content", newArticle.content);
      if (selectedImage) {
        formData.append("image", selectedImage);
      }

      const response = await axios.post("/api/articles", formData, {
        headers: {
          "Content-Type": "multipart/form-data",
        },
      });

      setArticles([...articles, response.data]);
      setNewArticle({ title: "", image: "", content: "" });
      setSelectedImage(null);
      setSuccessMessage("Article created successfully!");
    } catch (error: any) {
      console.error("Error creating article:", error);
      setErrorMessage(
        "Failed to create article. Please check the form and try again."
      );
    }
  };

  const formatDate = (dateString: string) => {
    return moment(dateString).format("MMMM D, YYYY");
  };

  return (
    <>
      <Head>
        <link
          rel="stylesheet"
          href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.2/css/all.min.css"
          integrity="sha512-SnH5WK+bZxgPHs44uWIX+LLJAJ9/2PkPKZ5QiAj6Ta86w+fsb2TkcmfRyVX3pBnMFcV7oQPJkl9QevSCWr3W6A=="
          crossOrigin="anonymous"
          referrerPolicy="no-referrer"
        />
      </Head>
      <header className={styles.header}>
        <div className={styles.headerLeft}>
          <button className={styles.thanhKeo} onClick={toggleSidebar}>
            ☰
          </button>

          <div className={styles.logo}>
            <Image src="/QR.png" alt="Logo" width={40} height={40} />
          </div>
          <div className={styles.headerTitle}>SHOP</div>
        </div>

        <div className={styles.headerIconsRight}>
          <a href="">
            <i className="fas fa-sign-out-alt"></i>
          </a>
        </div>
      </header>

      <div className={styles.container}>
        <aside
          id="sidebar"
          className={`${styles.sidebar} ${
            isSidebarHidden ? styles.hidden : ""
          }`}
          ref={sidebarRef}
        >
          <button className={styles.sidebarButton}>
            <i className=""></i>
            <Link href="" className={styles.sidebarLink}>
              Bảng Điều Khiển
            </Link>
          </button>
          <button className={styles.sidebarButton}>
            <i className=""></i>
            <Link href="" className={styles.sidebarLink}>
              Sản Phẩm
            </Link>
          </button>
          <button className={styles.sidebarButton}>
            <i className=""></i>
            <Link href="" className={styles.sidebarLink}>
              Danh Mục Sản Phẩm
            </Link>
          </button>
          <button className={styles.sidebarButton}>
            <i className=""></i>
            <Link href="#" className={styles.sidebarLink}>
              Tổng Danh Thu
            </Link>
          </button>
          <button className={styles.sidebarButton}>
            <i className=""></i>
            <Link href="" className={styles.sidebarLink}>
              Khách Hàng
            </Link>
          </button>
          <button className={styles.sidebarButton}>
            <i className=""></i>
            <Link href="" className={styles.sidebarLink}>
              Nhân Viên
            </Link>
          </button>
          <button className={styles.sidebarButton}>
            <i className=""></i>
            <Link href="#" className={styles.sidebarLink}>
              Đánh Giá
            </Link>
          </button>
          <button className={styles.sidebarButton}>
            <i className=""></i>
            <Link href="#" className={styles.sidebarLink}>
              Đơn Hàng
            </Link>
          </button>
          <button className={styles.sidebarButton}>
            <i className=""></i>
            <Link href="#" className={styles.sidebarLink}>
              Bài Viết
            </Link>
          </button>
          <button className={styles.sidebarButton}>
            <i className=""></i>
            <Link href="" className={styles.sidebarLink}>
              Khuyến Mãi
            </Link>
          </button>
        </aside>

        <main
          ref={mainContentRef}
          className={`${styles.mainContent} ${
            isSidebarHidden ? styles.expanded : ""
          }`}
        >
          <h1>Quản Lý Bài Viết</h1>

          {errorMessage && <div className={styles.error}>{errorMessage}</div>}
          {successMessage && (
            <div className={styles.success}>{successMessage}</div>
          )}

          <section className={styles.articlesSection}>
            <h2>Danh Sách Bài Viết</h2>
            <div className={styles.articleList}>
              {articles.map((article) => (
                <div key={article._id} className={styles.articleItem}>
                  {article.image && (
                    <img
                      src={`http://localhost:3001/${article.image}`} // Serve from backend
                      alt={article.title}
                      className={styles.articleImage}
                    />
                  )}
                  <h3>{article.title}</h3>
                  <p className={styles.articleDate}>
                    Ngày đăng: {formatDate(article.date)}
                  </p>
                  <p>{article.content.substring(0, 100)}...</p>
                  <Link href={`/article/${article._id}`}>Xem chi tiết</Link>
                </div>
              ))}
            </div>
          </section>

          <section className={styles.createArticleSection}>
            <h2>Thêm Bài Viết Mới</h2>
            <div className={styles.formGroup}>
              <label htmlFor="title">Tiêu Đề:</label>
              <input
                type="text"
                id="title"
                name="title"
                value={newArticle.title}
                onChange={handleInputChange}
              />
            </div>
            <div className={styles.formGroup}>
              <label htmlFor="image">Ảnh:</label>
              <input
                type="file"
                id="image"
                name="image"
                onChange={handleImageChange}
              />
            </div>
            <div className={styles.formGroup}>
              <label htmlFor="content">Nội Dung:</label>
              <textarea
                id="content"
                name="content"
                value={newArticle.content}
                onChange={handleInputChange}
              />
            </div>
            <button onClick={createArticle} className={styles.createButton}>
              Tạo Bài Viết
            </button>
          </section>
        </main>
      </div>
    </>
  );
};

export default HomeAdBaiViet;
